<template>
  <div class="login-container">
    <!--登录面板内容部分-->
    <div class="login-inner">
      <!--面板头部-->
      <div class="login-header">
        <h1>矿业大学ATM系统</h1>
        <div class="login-logo">
          <img :src="logo" alt="" width="70%">
        </div>
        
      </div>
      <!--面板表单部分-->
      <div class="login-content">
        <!--账号登录部分-->
        <el-form :label-position="'right'" label-width="80px">
          <el-form-item label="账号">
            <el-input v-model.trim="idcard" placeholder="账号"></el-input>
          </el-form-item>
          <el-form-item label="密码">
            <el-input show-password v-model.trim="password" placeholder="密码"></el-input>
          </el-form-item>
          <el-form-item label="身份">
            <el-radio v-model="userType" :label="1">用户</el-radio>
            <el-radio v-model="userType" :label="2">管理员</el-radio>
          </el-form-item>
          <el-form-item label="">
            <div style="text-align: center;">
              <el-button style="padding: 7px 15px;" type="primary" @click="goTo('/register')">去注册</el-button>
              <el-button style="padding: 7px 15px;" type="primary" @click="login">登录</el-button>
            </div>
          </el-form-item>
        </el-form>
      </div>
    </div>
  </div>
</template>

<script>
 import {
  adminLogin, // 管理员登录
  userLogin // 用户登录
} from '@/api/index'

  export default {
    name: "Login",
    data() {
      return {
        pwdMode: true, // 密码的显示方式 true 密文 false 明文
        password: '', // 密码
        idcard: '', // 账号
        userType: 1, // 身份
        logo: require("@/assets/logo.png"), // logo图片
      }
    },
    methods: {
      // 跳转
      goTo(path){
          this.$router.push(path);
      },
       resetData() {
        this.password= ''
        this.idcard = '';
      },
      // 登录
      async login() {
        console.log('请求一次');
        if(!this.idcard){
            this.$message.warning('请填写账号')
            return
        }
        if(!this.password){
            this.$message.warning('请填写密码')
            return
        }
        let params = {
          password: this.password
        }
        if(this.userType == 1){
          params.idcard = this.idcard
        }else {
          params.name = this.idcard
        }
        


        let res = this.userType == 1? await userLogin(params): await adminLogin(params)
        if (res.error) {
          this.$message.error(res.error);
          return;
        }
        console.log(res);
        if (res.token) {
          console.log(res);
          window.localStorage.setItem('token', res.token);
          this.resetData();
          params.userType = this.userType
          window.localStorage.setItem('userInfo', JSON.stringify(params));
          this.$bus.$emit('userInfoChange')
          this.$router.push('/admin');
        }
      },
    }
  }
</script>

<style scoped lang="stylus" rel="stylesheet/stylus">
  @import "../../common/stylus/mixins.styl"  
  .login-container::before {   // div是你需要添加背景图片的盒子
      content: "";
      background-image:  url('./images/bg.jpg');  // 背景图片的路径
      opacity: 0.9;
      background-size: 100% 100%;
      width: 100vw;
      height: 100vh;
      content: "";
      position: absolute;
      top: 0;
      left: 0;
      z-index: -1;/*-1 可以当背景*/
      -webkit-filter: blur(3px);
      filter: blur(3px);
    }
  .login-container
    width 100%
    height 100vh
    opacity: 1;
    position relative

    .login-left {
      height: 100%

      img {
        height: 100%
      }
    }
    
    .login-inner
      margin: 0 auto
      padding-top 5vh
      width 550px
      .login-header
        text-align: center
        color: white
        h1 {
          margin: 10px 0;
          font-family: cursive
          font-size: 3rem
        }
        .login-logo
          font-size 20px
          font-weight bold
          color mediumpurple
          text-align center
          >img {
            border-radius: 20px
            margin: 20px;
          }
          > a
            color #333
            font-size 14px
            padding-bottom 4px
            &:first-child
              margin-right 40px
            &.current
              color mediumpurple
              font-weight 700
              -bottom 2px solid mediumpurple
      .login-content
          margin: 10px;
          background-color: white;
          -radius: 5px;
          padding: 20px
          border-radius: 20px

</style>



